import type { Board, Direction, MoveResult } from './types';

const BOARD_SIZE = 4;

const cloneBoard = (board: Board): Board => board.map((row) => [...row]);

const boardsEqual = (left: Board, right: Board): boolean =>
  left.every((row, rowIndex) => row.every((cell, cellIndex) => cell === right[rowIndex][cellIndex]));

const getEmptyPositions = (board: Board): Array<{ row: number; col: number }> => {
  const empty: Array<{ row: number; col: number }> = [];

  board.forEach((row, rowIndex) => {
    row.forEach((cell, colIndex) => {
      if (cell === 0) {
        empty.push({ row: rowIndex, col: colIndex });
      }
    });
  });

  return empty;
};

const slideAndMergeRowLeft = (row: number[]) => {
  const filtered = row.filter((value) => value !== 0);
  const merged: number[] = [];
  let scoreGained = 0;

  for (let index = 0; index < filtered.length; index += 1) {
    const current = filtered[index];
    const next = filtered[index + 1];

    if (current !== 0 && current === next) {
      const mergedValue = current * 2;
      merged.push(mergedValue);
      scoreGained += mergedValue;
      index += 1;
    } else {
      merged.push(current);
    }
  }

  while (merged.length < BOARD_SIZE) {
    merged.push(0);
  }

  return { row: merged, scoreGained };
};

const transpose = (board: Board): Board =>
  board[0].map((_, colIndex) => board.map((row) => row[colIndex]));

const reverseRows = (board: Board): Board => board.map((row) => [...row].reverse());

const normalizeBoardForDirection = (board: Board, direction: Direction): Board => {
  switch (direction) {
    case 'left':
      return cloneBoard(board);
    case 'right':
      return reverseRows(board);
    case 'up':
      return transpose(board);
    case 'down':
      return reverseRows(transpose(board));
  }
};

const denormalizeBoardForDirection = (board: Board, direction: Direction): Board => {
  switch (direction) {
    case 'left':
      return board;
    case 'right':
      return reverseRows(board);
    case 'up':
      return transpose(board);
    case 'down':
      return transpose(reverseRows(board));
  }
};

export const createEmptyBoard = (): Board =>
  Array.from({ length: BOARD_SIZE }, () => Array.from({ length: BOARD_SIZE }, () => 0));

export const spawnRandomTile = (board: Board, random: () => number = Math.random): Board => {
  const emptyPositions = getEmptyPositions(board);
  if (emptyPositions.length === 0) {
    return cloneBoard(board);
  }

  const nextBoard = cloneBoard(board);
  const position = emptyPositions[Math.floor(random() * emptyPositions.length)];
  const value = random() < 0.9 ? 2 : 4;
  nextBoard[position.row][position.col] = value;
  return nextBoard;
};

export const createInitialBoard = (random: () => number = Math.random): Board => {
  const boardWithFirstTile = spawnRandomTile(createEmptyBoard(), random);
  return spawnRandomTile(boardWithFirstTile, random);
};

export const hasWinningTile = (board: Board): boolean => board.flat().some((value) => value >= 2048);

export const canMove = (board: Board): boolean => {
  if (getEmptyPositions(board).length > 0) {
    return true;
  }

  for (let rowIndex = 0; rowIndex < BOARD_SIZE; rowIndex += 1) {
    for (let colIndex = 0; colIndex < BOARD_SIZE; colIndex += 1) {
      const value = board[rowIndex][colIndex];
      if (rowIndex < BOARD_SIZE - 1 && board[rowIndex + 1][colIndex] === value) {
        return true;
      }
      if (colIndex < BOARD_SIZE - 1 && board[rowIndex][colIndex + 1] === value) {
        return true;
      }
    }
  }

  return false;
};

export const applyMove = (
  board: Board,
  direction: Direction,
  random: () => number = Math.random,
): MoveResult => {
  const normalized = normalizeBoardForDirection(board, direction);
  let scoreGained = 0;
  const movedBoard = normalized.map((row) => {
    const result = slideAndMergeRowLeft(row);
    scoreGained += result.scoreGained;
    return result.row;
  });

  const restoredBoard = denormalizeBoardForDirection(movedBoard, direction);
  const moved = !boardsEqual(board, restoredBoard);
  const finalBoard = moved ? spawnRandomTile(restoredBoard, random) : cloneBoard(board);
  const won = hasWinningTile(finalBoard);
  const gameOver = !canMove(finalBoard);

  return {
    board: finalBoard,
    scoreGained,
    moved,
    won,
    gameOver,
  };
};
