import { useCallback, useEffect, useMemo, useState } from 'react';
import './App.css';
import { GameBoard } from './components/GameBoard';
import { ScorePanel } from './components/ScorePanel';
import { applyMove, createInitialBoard } from './game/logic';
import type { Board, Direction } from './game/types';

const createGame = () => ({
  board: createInitialBoard(),
  score: 0,
  won: false,
  gameOver: false,
});

const keyDirectionMap: Record<string, Direction> = {
  ArrowUp: 'up',
  ArrowDown: 'down',
  ArrowLeft: 'left',
  ArrowRight: 'right',
  w: 'up',
  a: 'left',
  s: 'down',
  d: 'right',
  W: 'up',
  A: 'left',
  S: 'down',
  D: 'right',
};

function App() {
  const [board, setBoard] = useState<Board>(() => createGame().board);
  const [score, setScore] = useState(0);
  const [won, setWon] = useState(false);
  const [gameOver, setGameOver] = useState(false);

  const restart = useCallback(() => {
    const next = createGame();
    setBoard(next.board);
    setScore(next.score);
    setWon(next.won);
    setGameOver(next.gameOver);
  }, []);

  const handleMove = useCallback((direction: Direction) => {
    if (gameOver) {
      return;
    }

    setBoard((currentBoard) => {
      const result = applyMove(currentBoard, direction);
      if (!result.moved) {
        return currentBoard;
      }

      setScore((currentScore) => currentScore + result.scoreGained);
      setWon((currentWon) => currentWon || result.won);
      setGameOver(result.gameOver);
      return result.board;
    });
  }, [gameOver]);

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const direction = keyDirectionMap[event.key];
      if (!direction) {
        return;
      }

      event.preventDefault();
      handleMove(direction);
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [handleMove]);

  const status = useMemo(() => {
    if (gameOver) {
      return 'Game over';
    }
    if (won) {
      return 'You reached 2048!';
    }
    return 'Keep going';
  }, [gameOver, won]);

  return (
    <main className="app-shell">
      <section className="game-card">
        <header className="hero">
          <div>
            <p className="eyebrow">React + Vite + TypeScript</p>
            <h1>2048</h1>
            <p className="subtitle">Combine matching tiles until you reach 2048.</p>
          </div>
          <ScorePanel score={score} status={status} onRestart={restart} />
        </header>

        <GameBoard board={board} />

        <footer className="help-text">
          <p>Use Arrow keys or WASD to slide tiles.</p>
          <p>Merges add to your score. Moves that do nothing will not spawn a new tile.</p>
        </footer>
      </section>
    </main>
  );
}

export default App;
EOF

